"""Qualis journal classification lookup via PostgreSQL and Redis cache."""from __future__ import annotationsfrom functools import lru_cachefrom typing import Anyfrom apps.api.features.qualis.cache import QualisCache, QualisCacheKeysfrom apps.api.features.qualis.normalize import normalize_issn, normalize_titlefrom apps.api.features.qualis.repository import QualisRepository, get_qualis_repositoryfrom apps.api.features.qualis.scoring import estrato_score, resolve_qualis_classificationfrom apps.api.shared.observability.logging import get_loggerfrom apps.api.shared.settings import get_settingslogger = get_logger("postrec-qualis")_CACHE_MISS = object()class QualisService:    """Postgres-backed Qualis lookup with optional Redis cache-aside."""    def __init__(        self,        *,        repository: QualisRepository | None = None,        cache: QualisCache | None = None,    ) -> None:        self._repository = repository or get_qualis_repository()        self._cache = cache if cache is not None else QualisCache()        self._ready: bool | None = None    def _is_ready(self) -> bool:        if self._ready is not None:            return self._ready        if not get_settings().qualis_enabled:            self._ready = False            return self._ready        self._ready = self._repository.is_available()        if self._ready:            logger.info("qualis_service_ready")        else:            logger.warning("qualis_service_unavailable")        return self._ready    def reload(self) -> None:        self._ready = None        self._repository._available = None        self._repository._row_count = None        if self._cache.enabled:            self._cache.invalidate_all()    @property    def enabled(self) -> bool:        return get_settings().qualis_enabled    @property    def loaded(self) -> bool:        return self._is_ready()    @property    def row_count(self) -> int:        return self._repository.row_count()    def lookup(        self,        *,        issn: str | None = None,        title: str | None = None,        venue: str | None = None,    ) -> tuple[str | None, str | None]:        normalized_issn = normalize_issn(issn)        if normalized_issn:            estrato, period = self._lookup_by_issn(normalized_issn)            if estrato:                return estrato, period        for candidate in (title, venue):            normalized_title = normalize_title(candidate)            if not normalized_title:                continue            estrato, period = self._lookup_by_title(normalized_title)            if estrato:                return estrato, period        return None, None    def lookup_estrato(        self,        *,        issn: str | None = None,        title: str | None = None,        venue: str | None = None,    ) -> str | None:        estrato, _ = self.lookup(issn=issn, title=title, venue=venue)        return estrato    def lookup_score(        self,        *,        issn: str | None = None,        title: str | None = None,        venue: str | None = None,        weights: dict[str, float] | None = None,    ) -> tuple[float, str | None, str | None]:        estrato, period = self.lookup(issn=issn, title=title, venue=venue)        return estrato_score(estrato, weights=weights), estrato, period    def _lookup_by_issn(self, issn: str) -> tuple[str | None, str | None]:        cache_key = QualisCacheKeys.issn(issn)        cached = self._read_cache(cache_key)        if cached is not _CACHE_MISS:            return cached        classifications = self._repository.lookup_classifications_by_issn(issn)        estrato, period = resolve_qualis_classification(classifications)        self._write_cache(cache_key, estrato, period)        return estrato, period    def _lookup_by_title(self, title_normalized: str) -> tuple[str | None, str | None]:        cache_key = QualisCacheKeys.title(title_normalized)        cached = self._read_cache(cache_key)        if cached is not _CACHE_MISS:            return cached        classifications = self._repository.lookup_classifications_by_title(title_normalized)        estrato, period = resolve_qualis_classification(classifications)        self._write_cache(cache_key, estrato, period)        return estrato, period    def _read_cache(self, key: str) -> tuple[str | None, str | None] | object:        if not self._cache.enabled:            return _CACHE_MISS        payload = self._cache.get(key)        if payload is None:            return _CACHE_MISS        estrato = payload.get("estrato")        period = payload.get("period")        resolved_estrato = estrato if isinstance(estrato, str) else None        resolved_period = period if isinstance(period, str) else None        return resolved_estrato, resolved_period    def _write_cache(self, key: str, estrato: str | None, period: str | None) -> None:        self._cache.set(key, {"estrato": estrato, "period": period})    def boost_for_paper(self, paper: dict[str, Any]) -> tuple[float, str | None, str | None]:        """Return (additive boost, estrato, period) for a paper dict or SourceDocument-like payload."""        if not self.enabled or not self._is_ready():            return 0.0, None, None        metadata = paper.get("metadata") if isinstance(paper.get("metadata"), dict) else {}        issn = paper.get("issn") or metadata.get("issn")        journal_title = paper.get("journal_title") or metadata.get("journal_title")        venue = paper.get("venue")        score, estrato, period = self.lookup_score(            issn=issn,            title=journal_title,            venue=venue,        )        if score <= 0.0:            return 0.0, estrato, period        boost = get_settings().qualis_boost_weight * score        return round(boost, 4), estrato, period    def apply_relevance_boost(self, base_score: float, paper: dict[str, Any]) -> tuple[float, dict[str, Any]]:        """Add Qualis boost to a relevance score and return enrichment metadata."""        boost, estrato, period = self.boost_for_paper(paper)        if boost <= 0.0 and estrato is None:            return base_score, {}        boosted = max(0.0, min(1.0, base_score + boost))        meta: dict[str, Any] = {            "qualis_estrato": estrato,            "qualis_boost": boost,        }        if period:            meta["qualis_period"] = period        return round(boosted, 4), meta@lru_cachedef _qualis_service_singleton() -> QualisService:    return QualisService()qualis_service = _qualis_service_singleton()